{
  "name": "Gestão AD Aguiarnópolis",
  "description": "Sistema completo para gestão de membros da Assembleia de Deus em Aguiarnópolis, com controle de categorias (crianças, jovens, adultos) e aniversariantes.",
  "requestFramePermissions": ["camera"]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum MemberCategory {
  CHILD = 'Criança',
  YOUTH = 'Jovem',
  ADULT = 'Adulto',
  ELDER = 'Idoso'
}

export enum Gender {
  MALE = 'Masculino',
  FEMALE = 'Feminino'
}

export interface Member {
  id: string;
  name: string;
  birthDate: string;
  category: MemberCategory;
  gender: Gender;
  phone: string;
  address: string;
  baptismDate?: string;
  department?: string;
  photoUrl?: string;
  createdAt: string;
}

export type ViewType = 'dashboard' | 'members' | 'register' | 'birthdays' | 'ai-assistant';

import React from 'react';

export const CHURCH_NAME = "Assembleia de Deus em Aguiarnópolis";

export const COLORS = {
  primary: '#1e3a8a', // Navy blue
  secondary: '#b45309', // Amber/Gold
  accent: '#2563eb', // Blue
};

export const DEPARTMENTS = [
  "Crianças (Sementinhas)",
  "Jovens (UMADAG)",
  "Senhoras (Círculo de Oração)",
  "Varões (Gideões)",
  "Escola Bíblica Dominical",
  "Louvor/Música",
  "Missões"
];

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Users, 
  UserPlus, 
  LayoutDashboard, 
  Gift, 
  Menu, 
  X, 
  Church,
  Sparkles,
  Search,
  Trash2,
  Edit,
  ChevronRight
} from 'lucide-react';
import { Member, MemberCategory, ViewType } from './types';
import Dashboard from './components/Dashboard';
import MemberList from './components/MemberList';
import MemberForm from './components/MemberForm';
import BirthdayList from './components/BirthdayList';
import AIAssistant from './components/AIAssistant';
import { CHURCH_NAME } from './constants';

const App: React.FC = () => {
  const [members, setMembers] = useState<Member[]>([]);
  const [currentView, setCurrentView] = useState<ViewType>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [editingMember, setEditingMember] = useState<Member | null>(null);

  // Persistence
  useEffect(() => {
    const saved = localStorage.getItem('ad_aguiarnopolis_members');
    if (saved) {
      try {
        setMembers(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to load members", e);
      }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('ad_aguiarnopolis_members', JSON.stringify(members));
  }, [members]);

  const addMember = (newMember: Member) => {
    setMembers(prev => [...prev, newMember]);
    setCurrentView('members');
  };

  const updateMember = (updated: Member) => {
    setMembers(prev => prev.map(m => m.id === updated.id ? updated : m));
    setEditingMember(null);
    setCurrentView('members');
  };

  const deleteMember = (id: string) => {
    if (confirm('Tem certeza que deseja excluir este membro?')) {
      setMembers(prev => prev.filter(m => m.id !== id));
    }
  };

  const handleEdit = (member: Member) => {
    setEditingMember(member);
    setCurrentView('register');
  };

  const NavItem = ({ view, icon: Icon, label }: { view: ViewType, icon: any, label: string }) => (
    <button
      onClick={() => {
        setCurrentView(view);
        setEditingMember(null);
        setIsSidebarOpen(false);
      }}
      className={`flex items-center space-x-3 w-full px-4 py-3 rounded-lg transition-colors ${
        currentView === view 
          ? 'bg-blue-600 text-white shadow-md' 
          : 'text-gray-600 hover:bg-blue-50 hover:text-blue-600'
      }`}
    >
      <Icon size={20} />
      <span className="font-medium">{label}</span>
    </button>
  );

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-gray-50">
      {/* Mobile Header */}
      <header className="md:hidden bg-blue-900 text-white p-4 flex justify-between items-center sticky top-0 z-50 shadow-md">
        <div className="flex items-center space-x-2">
          <Church size={24} className="text-amber-400" />
          <h1 className="text-lg font-bold truncate">AD Aguiarnópolis</h1>
        </div>
        <button onClick={() => setIsSidebarOpen(!isSidebarOpen)}>
          {isSidebarOpen ? <X size={28} /> : <Menu size={28} />}
        </button>
      </header>

      {/* Sidebar Overlay */}
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black bg-opacity-50 z-40 md:hidden"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      {/* Sidebar */}
      <aside className={`
        fixed inset-y-0 left-0 transform ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
        md:relative md:translate-x-0 transition duration-200 ease-in-out
        z-50 w-64 bg-white border-r border-gray-200 flex flex-col h-full
      `}>
        <div className="p-6 border-b border-gray-100 hidden md:block">
          <div className="flex items-center space-x-2 mb-2">
            <Church size={32} className="text-blue-700" />
            <span className="text-blue-900 font-bold text-xl leading-tight">AD Aguiarnópolis</span>
          </div>
          <p className="text-xs text-gray-400 uppercase tracking-widest font-semibold">Gestão de Membros</p>
        </div>

        <nav className="flex-1 px-4 py-6 space-y-2">
          <NavItem view="dashboard" icon={LayoutDashboard} label="Dashboard" />
          <NavItem view="members" icon={Users} label="Membros" />
          <NavItem view="register" icon={UserPlus} label={editingMember ? "Editar Membro" : "Novo Membro"} />
          <NavItem view="birthdays" icon={Gift} label="Aniversariantes" />
          <NavItem view="ai-assistant" icon={Sparkles} label="Assistente IA" />
        </nav>

        <div className="p-4 border-t border-gray-100">
          <div className="bg-blue-50 p-4 rounded-xl">
            <p className="text-xs text-blue-800 font-medium">Total de Membros</p>
            <p className="text-2xl font-bold text-blue-900">{members.length}</p>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto p-4 md:p-8">
        <div className="max-w-6xl mx-auto">
          {currentView === 'dashboard' && <Dashboard members={members} onNavigate={setCurrentView} />}
          {currentView === 'members' && (
            <MemberList 
              members={members} 
              onDelete={deleteMember} 
              onEdit={handleEdit} 
            />
          )}
          {currentView === 'register' && (
            <MemberForm 
              onSave={editingMember ? updateMember : addMember} 
              initialData={editingMember} 
              onCancel={() => {
                setEditingMember(null);
                setCurrentView('members');
              }}
            />
          )}
          {currentView === 'birthdays' && <BirthdayList members={members} />}
          {currentView === 'ai-assistant' && <AIAssistant members={members} />}
        </div>
      </main>
    </div>
  );
};

export default App;

import React from 'react';
import { 
  Users, 
  Baby, 
  UserCircle, 
  Cake, 
  TrendingUp,
  Award
} from 'lucide-react';
import { Member, MemberCategory, ViewType } from '../types';
import { PieChart, Pie, Cell, ResponsiveContainer, BarChart, Bar, XAxis, YAxis, Tooltip, Legend } from 'recharts';

interface DashboardProps {
  members: Member[];
  onNavigate: (view: ViewType) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ members, onNavigate }) => {
  const currentMonth = new Date().getMonth();

  const stats = {
    total: members.length,
    children: members.filter(m => m.category === MemberCategory.CHILD).length,
    youth: members.filter(m => m.category === MemberCategory.YOUTH).length,
    adults: members.filter(m => m.category === MemberCategory.ADULT || m.category === MemberCategory.ELDER).length,
    baptized: members.filter(m => m.baptismDate).length,
    birthdaysThisMonth: members.filter(m => {
      const bDate = new Date(m.birthDate);
      return bDate.getMonth() === currentMonth;
    }).length,
  };

  const categoryData = [
    { name: 'Crianças', value: stats.children, color: '#3b82f6' },
    { name: 'Jovens', value: stats.youth, color: '#10b981' },
    { name: 'Adultos/Idosos', value: stats.adults, color: '#f59e0b' },
  ];

  const genderData = [
    { 
      name: 'Gênero', 
      Masculino: members.filter(m => m.gender === 'Masculino').length,
      Feminino: members.filter(m => m.gender === 'Feminino').length 
    }
  ];

  const StatCard = ({ title, value, icon: Icon, colorClass, onClick }: any) => (
    <div 
      onClick={onClick}
      className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex items-center justify-between cursor-pointer hover:shadow-md transition-shadow"
    >
      <div>
        <p className="text-sm font-medium text-gray-500 mb-1">{title}</p>
        <p className="text-3xl font-bold text-gray-900">{value}</p>
      </div>
      <div className={`p-3 rounded-xl ${colorClass}`}>
        <Icon size={24} />
      </div>
    </div>
  );

  return (
    <div className="space-y-8">
      <header>
        <h2 className="text-3xl font-bold text-gray-900">Olá, bem-vindo!</h2>
        <p className="text-gray-500">Aqui está o resumo atual da igreja em Aguiarnópolis.</p>
      </header>

      {/* Grid Stats */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard 
          title="Total de Membros" 
          value={stats.total} 
          icon={Users} 
          colorClass="bg-blue-100 text-blue-600" 
          onClick={() => onNavigate('members')}
        />
        <StatCard 
          title="Aniversariantes (Mês)" 
          value={stats.birthdaysThisMonth} 
          icon={Cake} 
          colorClass="bg-pink-100 text-pink-600"
          onClick={() => onNavigate('birthdays')}
        />
        <StatCard 
          title="Batizados" 
          value={stats.baptized} 
          icon={Award} 
          colorClass="bg-indigo-100 text-indigo-600" 
          onClick={() => onNavigate('members')}
        />
        <StatCard 
          title="Crianças" 
          value={stats.children} 
          icon={Baby} 
          colorClass="bg-green-100 text-green-600" 
          onClick={() => onNavigate('members')}
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Category Chart */}
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
          <h3 className="text-lg font-bold text-gray-900 mb-6">Distribuição por Categoria</h3>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={categoryData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {categoryData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color} />
                  ))}
                </Pie>
                <Tooltip />
                <Legend verticalAlign="bottom" height={36}/>
              </PieChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Gender Bar Chart */}
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
          <h3 className="text-lg font-bold text-gray-900 mb-6">Membros por Gênero</h3>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={genderData}>
                <XAxis dataKey="name" />
                <YAxis />
                <Tooltip cursor={{fill: 'transparent'}} />
                <Legend />
                <Bar dataKey="Masculino" fill="#1d4ed8" radius={[4, 4, 0, 0]} />
                <Bar dataKey="Feminino" fill="#ec4899" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

      {/* Quick Actions */}
      <div className="bg-blue-900 text-white p-8 rounded-3xl flex flex-col md:flex-row items-center justify-between gap-6 shadow-xl relative overflow-hidden">
        <div className="relative z-10">
          <h3 className="text-2xl font-bold mb-2">Novo Membro Chegando?</h3>
          <p className="text-blue-100 mb-4">Adicione rapidamente novos membros para manter o registro da igreja atualizado.</p>
          <button 
            onClick={() => onNavigate('register')}
            className="bg-white text-blue-900 px-6 py-3 rounded-xl font-bold hover:bg-blue-50 transition-colors shadow-lg"
          >
            Cadastrar Novo Membro
          </button>
        </div>
        <div className="relative z-10 hidden md:block opacity-20 transform scale-150">
          <Church size={120} />
        </div>
        {/* Decorative elements */}
        <div className="absolute top-0 right-0 -mt-8 -mr-8 w-64 h-64 bg-blue-800 rounded-full opacity-50"></div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { Member, MemberCategory, Gender } from '../types';
import { Camera, Save, ArrowLeft, Calendar, User, Phone, Home, MapPin } from 'lucide-react';
import { DEPARTMENTS } from '../constants';

interface MemberFormProps {
  onSave: (member: Member) => void;
  initialData?: Member | null;
  onCancel: () => void;
}

const MemberForm: React.FC<MemberFormProps> = ({ onSave, initialData, onCancel }) => {
  const [formData, setFormData] = useState<Partial<Member>>({
    name: '',
    birthDate: '',
    category: MemberCategory.ADULT,
    gender: Gender.MALE,
    phone: '',
    address: '',
    department: DEPARTMENTS[0],
    ...initialData
  });

  const [photoPreview, setPhotoPreview] = useState<string | undefined>(initialData?.photoUrl);

  const handlePhotoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64 = reader.result as string;
        setPhotoPreview(base64);
        setFormData(prev => ({ ...prev, photoUrl: base64 }));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.birthDate) {
      alert('Por favor, preencha nome e data de nascimento.');
      return;
    }

    const member: Member = {
      ...(formData as Member),
      id: initialData?.id || Date.now().toString(),
      createdAt: initialData?.createdAt || new Date().toISOString(),
    };

    onSave(member);
  };

  const calculateCategory = (birthDate: string) => {
    if (!birthDate) return MemberCategory.ADULT;
    const age = Math.floor((new Date().getTime() - new Date(birthDate).getTime()) / 31557600000);
    if (age < 12) return MemberCategory.CHILD;
    if (age < 18) return MemberCategory.YOUTH;
    if (age > 60) return MemberCategory.ELDER;
    return MemberCategory.ADULT;
  };

  const InputField = ({ label, icon: Icon, children }: any) => (
    <div className="space-y-1">
      <label className="text-sm font-semibold text-gray-700 block ml-1">{label}</label>
      <div className="relative">
        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
          <Icon size={18} />
        </div>
        {children}
      </div>
    </div>
  );

  return (
    <div className="bg-white rounded-3xl shadow-xl overflow-hidden max-w-4xl mx-auto border border-gray-100">
      <div className="bg-blue-700 p-6 md:p-10 text-white flex justify-between items-center">
        <div>
          <h2 className="text-2xl md:text-3xl font-bold">{initialData ? 'Editar Registro' : 'Cadastro de Membro'}</h2>
          <p className="text-blue-100 mt-1">Insira as informações do membro da Assembleia de Deus.</p>
        </div>
        <button 
          onClick={onCancel}
          className="bg-white/10 hover:bg-white/20 p-2 rounded-full transition-colors"
        >
          <ArrowLeft size={24} />
        </button>
      </div>

      <form onSubmit={handleSubmit} className="p-6 md:p-10 space-y-8">
        <div className="flex flex-col md:flex-row gap-10">
          {/* Photo Upload */}
          <div className="flex flex-col items-center space-y-4">
            <div className="w-40 h-40 rounded-3xl bg-gray-100 border-4 border-white shadow-lg overflow-hidden relative group">
              {photoPreview ? (
                <img src={photoPreview} alt="Preview" className="w-full h-full object-cover" />
              ) : (
                <div className="w-full h-full flex flex-col items-center justify-center text-gray-400">
                  <User size={64} strokeWidth={1} />
                  <span className="text-xs font-medium uppercase mt-2">Sem Foto</span>
                </div>
              )}
              <label className="absolute inset-0 bg-black/40 flex items-center justify-center opacity-0 group-hover:opacity-100 cursor-pointer transition-opacity">
                <Camera className="text-white" size={32} />
                <input type="file" className="hidden" accept="image/*" onChange={handlePhotoChange} />
              </label>
            </div>
            <p className="text-xs text-gray-500 text-center max-w-[160px]">Recomendamos uma foto clara estilo 3x4.</p>
          </div>

          {/* Form Fields */}
          <div className="flex-1 grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="md:col-span-2">
              <InputField label="Nome Completo" icon={User}>
                <input
                  type="text"
                  value={formData.name}
                  onChange={e => setFormData({ ...formData, name: e.target.value })}
                  className="w-full pl-10 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none"
                  placeholder="Nome do membro"
                />
              </InputField>
            </div>

            <InputField label="Data de Nascimento" icon={Calendar}>
              <input
                type="date"
                value={formData.birthDate}
                onChange={e => {
                  const val = e.target.value;
                  setFormData({ 
                    ...formData, 
                    birthDate: val,
                    category: calculateCategory(val)
                  });
                }}
                className="w-full pl-10 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none"
              />
            </InputField>

            <InputField label="Categoria (Automática)" icon={TrendingUp}>
              <select
                value={formData.category}
                onChange={e => setFormData({ ...formData, category: e.target.value as MemberCategory })}
                className="w-full pl-10 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none appearance-none"
              >
                {Object.values(MemberCategory).map(cat => (
                  <option key={cat} value={cat}>{cat}</option>
                ))}
              </select>
            </InputField>

            <InputField label="Gênero" icon={User}>
              <select
                value={formData.gender}
                onChange={e => setFormData({ ...formData, gender: e.target.value as Gender })}
                className="w-full pl-10 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none appearance-none"
              >
                <option value={Gender.MALE}>Masculino</option>
                <option value={Gender.FEMALE}>Feminino</option>
              </select>
            </InputField>

            <InputField label="WhatsApp / Telefone" icon={Phone}>
              <input
                type="text"
                value={formData.phone}
                onChange={e => setFormData({ ...formData, phone: e.target.value })}
                className="w-full pl-10 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none"
                placeholder="(63) 90000-0000"
              />
            </InputField>

            <div className="md:col-span-2">
              <InputField label="Endereço" icon={MapPin}>
                <input
                  type="text"
                  value={formData.address}
                  onChange={e => setFormData({ ...formData, address: e.target.value })}
                  className="w-full pl-10 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none"
                  placeholder="Rua, Bairro, Número"
                />
              </InputField>
            </div>

            <InputField label="Data de Batismo" icon={Calendar}>
              <input
                type="date"
                value={formData.baptismDate}
                onChange={e => setFormData({ ...formData, baptismDate: e.target.value })}
                className="w-full pl-10 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none"
              />
            </InputField>

            <InputField label="Departamento Principal" icon={Home}>
              <select
                value={formData.department}
                onChange={e => setFormData({ ...formData, department: e.target.value })}
                className="w-full pl-10 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none appearance-none"
              >
                <option value="">Nenhum</option>
                {DEPARTMENTS.map(dept => (
                  <option key={dept} value={dept}>{dept}</option>
                ))}
              </select>
            </InputField>
          </div>
        </div>

        <div className="flex justify-end space-x-4 pt-6 border-t border-gray-100">
          <button
            type="button"
            onClick={onCancel}
            className="px-8 py-3 bg-gray-100 text-gray-700 rounded-xl font-bold hover:bg-gray-200 transition-colors"
          >
            Cancelar
          </button>
          <button
            type="submit"
            className="px-10 py-3 bg-blue-700 text-white rounded-xl font-bold hover:bg-blue-800 transition-colors shadow-lg flex items-center space-x-2"
          >
            <Save size={20} />
            <span>Salvar Registro</span>
          </button>
        </div>
      </form>
    </div>
  );
};

export default MemberForm;

import React, { useState, useMemo } from 'react';
import { Member, MemberCategory } from '../types';
import { 
  Search, 
  Filter, 
  MoreVertical, 
  Trash2, 
  Edit, 
  User, 
  Phone,
  Cake,
  Calendar,
  X
} from 'lucide-react';

interface MemberListProps {
  members: Member[];
  onDelete: (id: string) => void;
  onEdit: (member: Member) => void;
}

const MemberList: React.FC<MemberListProps> = ({ members, onDelete, onEdit }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [categoryFilter, setCategoryFilter] = useState<string>('all');
  const [activeMenu, setActiveMenu] = useState<string | null>(null);

  const filteredMembers = useMemo(() => {
    return members.filter(member => {
      const matchesSearch = member.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
                          member.phone.includes(searchTerm);
      const matchesCategory = categoryFilter === 'all' || member.category === categoryFilter;
      return matchesSearch && matchesCategory;
    });
  }, [members, searchTerm, categoryFilter]);

  const formatDate = (dateStr: string) => {
    if (!dateStr) return 'Não informado';
    return new Date(dateStr).toLocaleDateString('pt-BR');
  };

  const getCategoryBadgeColor = (cat: MemberCategory) => {
    switch (cat) {
      case MemberCategory.CHILD: return 'bg-green-100 text-green-700';
      case MemberCategory.YOUTH: return 'bg-blue-100 text-blue-700';
      case MemberCategory.ADULT: return 'bg-amber-100 text-amber-700';
      case MemberCategory.ELDER: return 'bg-purple-100 text-purple-700';
      default: return 'bg-gray-100 text-gray-700';
    }
  };

  return (
    <div className="space-y-6">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
