import React from 'react';
import { Member } from '../types';
import { Gift, Calendar, ChevronRight } from 'lucide-react';

interface BirthdayListProps {
  members: Member[];
}

const BirthdayList: React.FC<BirthdayListProps> = ({ members }) => {
  const months = [
    'Janeiro', 'Fevereiro', 'Março', 'Abril', 'Maio', 'Junho',
    'Julho', 'Agosto', 'Setembro', 'Outubro', 'Novembro', 'Dezembro'
  ];

  const currentMonth = new Date().getMonth();

  const getBirthdaysByMonth = (monthIdx: number) => {
    return members
      .filter(m => new Date(m.birthDate).getMonth() === monthIdx)
      .sort((a, b) => new Date(a.birthDate).getDate() - new Date(b.birthDate).getDate());
  };

  return (
    <div className="space-y-8 pb-12">
      <header className="bg-gradient-to-r from-pink-600 to-rose-500 p-8 rounded-3xl text-white shadow-lg">
        <div className="flex items-center space-x-4 mb-2">
          <div className="p-3 bg-white/20 rounded-2xl">
            <Gift size={32} />
          </div>
          <h2 className="text-3xl font-bold">Aniversariantes</h2>
        </div>
        <p className="text-pink-100">Celebre a vida de cada irmão em nossa congregação.</p>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        {months.map((month, idx) => {
          const birthdayPeople = getBirthdaysByMonth(idx);
          const isCurrent = idx === currentMonth;

          return (
            <div 
              key={month} 
              className={`bg-white rounded-3xl shadow-sm border ${isCurrent ? 'border-pink-300 ring-4 ring-pink-50' : 'border-gray-100'} overflow-hidden transition-all hover:shadow-md`}
            >
              <div className={`p-4 ${isCurrent ? 'bg-pink-500 text-white' : 'bg-gray-50 text-gray-700'} flex justify-between items-center`}>
                <h3 className="font-bold text-lg">{month}</h3>
                {isCurrent && <span className="text-xs font-bold uppercase bg-white/20 px-2 py-1 rounded">Mês Atual</span>}
              </div>
              <div className="p-4">
                {birthdayPeople.length > 0 ? (
                  <ul className="space-y-4">
                    {birthdayPeople.map(person => (
                      <li key={person.id} className="flex items-center justify-between group">
                        <div className="flex items-center space-x-3">
                          <div className="w-10 h-10 rounded-full bg-pink-100 flex items-center justify-center text-pink-600 font-bold text-sm">
                            {new Date(person.birthDate).getDate()}
                          </div>
                          <div>
                            <p className="font-semibold text-gray-900 group-hover:text-pink-600 transition-colors">{person.name}</p>
                            <p className="text-xs text-gray-500">{person.category}</p>
                          </div>
                        </div>
                        <ChevronRight size={16} className="text-gray-300" />
                      </li>
                    ))}
                  </ul>
                ) : (
                  <p className="text-sm text-gray-400 italic text-center py-4">Nenhum aniversariante</p>
                )}
