import React, { useState } from 'react';
import { GoogleGenAI } from "@google/genai";
import { Member } from '../types';
import { Sparkles, MessageSquare, BookOpen, Send, Loader2, User, Church } from 'lucide-react';

interface AIAssistantProps {
  members: Member[];
}

const AIAssistant: React.FC<AIAssistantProps> = ({ members }) => {
  const [selectedMemberId, setSelectedMemberId] = useState('');
  const [loading, setLoading] = useState(false);
  const [response, setResponse] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  const generateSpiritualInsight = async (type: 'prayer' | 'devotional') => {
    if (!selectedMemberId) {
      alert('Selecione um membro primeiro.');
      return;
    }

    const member = members.find(m => m.id === selectedMemberId);
    if (!member) return;

    setLoading(true);
    setError(null);
    setResponse(null);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = type === 'prayer' 
        ? `Escreva um pequeno texto de oração e encorajamento personalizado para um membro da igreja chamado ${member.name}, que é da categoria ${member.category}. Use uma linguagem cristã acolhedora e cite um versículo bíblico apropriado.`
        : `Como líder da igreja Assembleia de Deus, escreva uma breve mensagem devocional para o irmão(a) ${member.name} (Categoria: ${member.category}). Fale sobre o valor da sua presença na congregação em Aguiarnópolis e deseje bênçãos sobre sua vida.`;

      const result = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });

      setResponse(result.text || 'Não foi possível gerar a mensagem.');
    } catch (err) {
      console.error(err);
      setError('Houve um erro ao consultar a inteligência espiritual. Tente novamente mais tarde.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-3xl mx-auto space-y-8">
      <header className="text-center space-y-2">
        <div className="inline-flex p-4 bg-blue-100 text-blue-700 rounded-3xl mb-4">
          <Sparkles size={32} />
        </div>
        <h2 className="text-3xl font-bold text-gray-900">Assistente Espiritual IA</h2>
        <p className="text-gray-500">Use nossa IA para gerar mensagens de oração e devocionais personalizados para os membros.</p>
      </header>

      <div className="bg-white rounded-3xl p-8 shadow-sm border border-gray-100 space-y-6">
        <div className="space-y-4">
          <label className="text-sm font-bold text-gray-700 block ml-1">Selecione o Membro</label>
          <div className="relative">
            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
              <User size={20} />
            </div>
            <select
              value={selectedMemberId}
              onChange={e => setSelectedMemberId(e.target.value)}
              className="w-full pl-10 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none appearance-none cursor-pointer"
            >
              <option value="">Escolher da lista...</option>
              {members.map(m => (
                <option key={m.id} value={m.id}>{m.name} ({m.category})</option>
              ))}
            </select>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <button
            onClick={() => generateSpiritualInsight('prayer')}
            disabled={loading || !selectedMemberId}
            className="flex items-center justify-center space-x-2 p-4 bg-blue-700 text-white rounded-2xl font-bold hover:bg-blue-800 transition-all disabled:opacity-50 shadow-md"
          >
            {loading ? <Loader2 size={20} className="animate-spin" /> : <MessageSquare size={20} />}
            <span>Gerar Oração</span>
          </button>

          <button
            onClick={() => generateSpiritualInsight('devotional')}
            disabled={loading || !selectedMemberId}
            className="flex items-center justify-center space-x-2 p-4 bg-amber-600 text-white rounded-2xl font-bold hover:bg-amber-700 transition-all disabled:opacity-50 shadow-md"
          >
            {loading ? <Loader2 size={20} className="animate-spin" /> : <BookOpen size={20} />}
            <span>Mensagem Devocional</span>
          </button>
        </div>
      </div>

      {error && (
        <div className="bg-red-50 text-red-700 p-6 rounded-2xl border border-red-100 animate-pulse">
          {error}
        </div>
      )}

      {response && (
        <div className="bg-white rounded-3xl p-8 shadow-lg border-2 border-blue-50 relative overflow-hidden animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div className="absolute top-0 right-0 p-4 opacity-10">
            <Church size={80} />
          </div>
          <div className="relative z-10 prose prose-blue max-w-none">
            <h3 className="text-blue-900 font-bold text-xl mb-4 flex items-center">
              <Sparkles className="mr-2 text-amber-400" size={24} />
              Mensagem Inspirada
            </h3>
            <div className="whitespace-pre-wrap text-gray-700 leading-relaxed italic">
              "{response}"
            </div>
            <div className="mt-8 pt-6 border-t border-gray-100 flex justify-between items-center text-xs text-gray-400 italic">
              <span>Gerado via IA para AD Aguiarnópolis</span>
              <button 
                onClick={() => {
                  navigator.clipboard.writeText(response);
                  alert('Mensagem copiada!');
                }}
                className="text-blue-600 font-bold hover:underline uppercase tracking-wider"
              >
                Copiar Texto
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AIAssistant;

