import React, { useState, useMemo } from 'react';
import { Member, MemberCategory } from '../types';
import { 
  Search, 
  Filter, 
  MoreVertical, 
  Trash2, 
  Edit, 
  User, 
  Phone,
  Cake,
  Calendar,
  X,
  Users
} from 'lucide-react';

interface MemberListProps {
  members: Member[];
  onDelete: (id: string) => void;
  onEdit: (member: Member) => void;
}

const MemberList: React.FC<MemberListProps> = ({ members, onDelete, onEdit }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [categoryFilter, setCategoryFilter] = useState<string>('all');
  const [activeMenu, setActiveMenu] = useState<string | null>(null);

  const filteredMembers = useMemo(() => {
    return members.filter(member => {
      const matchesSearch = member.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
                          member.phone.includes(searchTerm);
      const matchesCategory = categoryFilter === 'all' || member.category === categoryFilter;
      return matchesSearch && matchesCategory;
    });
  }, [members, searchTerm, categoryFilter]);

  const formatDate = (dateStr: string) => {
    if (!dateStr) return 'Não informado';
    return new Date(dateStr).toLocaleDateString('pt-BR');
  };

  const getCategoryBadgeColor = (cat: MemberCategory) => {
    switch (cat) {
      case MemberCategory.CHILD: return 'bg-green-100 text-green-700';
      case MemberCategory.YOUTH: return 'bg-blue-100 text-blue-700';
      case MemberCategory.ADULT: return 'bg-amber-100 text-amber-700';
      case MemberCategory.ELDER: return 'bg-purple-100 text-purple-700';
      default: return 'bg-gray-100 text-gray-700';
    }
  };

  return (
    <div className="space-y-6">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-2xl font-bold text-gray-900">Membros Registrados</h2>
          <p className="text-gray-500">Gerencie o rol de membros da congregação.</p>
        </div>

        <div className="flex flex-col md:flex-row gap-4">
          <div className="relative group">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-blue-500 transition-colors" size={20} />
            <input
              type="text"
              placeholder="Buscar por nome ou fone..."
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
              className="pl-10 pr-4 py-3 bg-white border border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none w-full md:w-64 shadow-sm"
            />
          </div>

          <div className="relative">
            <Filter className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
            <select
              value={categoryFilter}
              onChange={e => setCategoryFilter(e.target.value)}
              className="pl-10 pr-8 py-3 bg-white border border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none shadow-sm appearance-none cursor-pointer"
            >
              <option value="all">Todas Categorias</option>
              {Object.values(MemberCategory).map(cat => (
                <option key={cat} value={cat}>{cat}</option>
              ))}
            </select>
          </div>
        </div>
      </header>

      {/* Grid view for members */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredMembers.length > 0 ? (
          filteredMembers.map(member => (
            <div key={member.id} className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden group hover:shadow-md transition-shadow relative">
              <div className="p-6">
                <div className="flex items-start justify-between mb-4">
                  <div className="flex items-center space-x-4">
                    <div className="w-16 h-16 rounded-2xl bg-gray-100 overflow-hidden shadow-inner flex-shrink-0">
                      {member.photoUrl ? (
                        <img src={member.photoUrl} alt={member.name} className="w-full h-full object-cover" />
                      ) : (
                        <div className="w-full h-full flex items-center justify-center text-gray-300">
                          <User size={32} />
                        </div>
                      )}
                    </div>
                    <div>
                      <h3 className="font-bold text-gray-900 leading-tight">{member.name}</h3>
                      <span className={`text-xs font-bold uppercase tracking-wider px-2 py-1 rounded-md mt-1 inline-block ${getCategoryBadgeColor(member.category)}`}>
                        {member.category}
                      </span>
                    </div>
                  </div>

                  <div className="relative">
                    <button 
                      onClick={() => setActiveMenu(activeMenu === member.id ? null : member.id)}
                      className="p-1 hover:bg-gray-100 rounded-lg text-gray-400"
                    >
                      <MoreVertical size={20} />
                    </button>

                    {activeMenu === member.id && (
                      <>
                        <div className="fixed inset-0 z-10" onClick={() => setActiveMenu(null)}></div>
                        <div className="absolute right-0 top-full mt-2 w-40 bg-white border border-gray-100 shadow-xl rounded-xl z-20 overflow-hidden">
                          <button 
                            onClick={() => { onEdit(member); setActiveMenu(null); }}
                            className="w-full flex items-center space-x-2 px-4 py-3 text-sm text-gray-700 hover:bg-blue-50 hover:text-blue-700 transition-colors"
                          >
                            <Edit size={16} />
                            <span>Editar</span>
                          </button>
                          <button 
                            onClick={() => { onDelete(member.id); setActiveMenu(null); }}
                            className="w-full flex items-center space-x-2 px-4 py-3 text-sm text-red-600 hover:bg-red-50 transition-colors border-t border-gray-50"
                          >
                            <Trash2 size={16} />
                            <span>Excluir</span>
                          </button>
                        </div>
                      </>
                    )}
                  </div>
                </div>

                <div className="space-y-3 pt-4 border-t border-gray-50">
                  <div className="flex items-center text-sm text-gray-600">
                    <Cake size={16} className="mr-3 text-pink-500" />
                    <span>Nasc: {formatDate(member.birthDate)}</span>
                  </div>
                  <div className="flex items-center text-sm text-gray-600">
                    <Phone size={16} className="mr-3 text-green-500" />
                    <span>{member.phone || 'N/A'}</span>
                  </div>
                  {member.baptismDate && (
                    <div className="flex items-center text-sm text-gray-600">
                      <Calendar size={16} className="mr-3 text-blue-500" />
                      <span>Batismo: {formatDate(member.baptismDate)}</span>
                    </div>
                  )}
                  {member.department && (
                    <div className="flex items-center text-xs text-gray-400 bg-gray-50 px-2 py-1 rounded-lg">
                      <span className="font-semibold uppercase mr-2">Dept:</span>
                      {member.department}
                    </div>
                  )}
                </div>
              </div>
            </div>
          ))
        ) : (
          <div className="col-span-full py-20 bg-white rounded-3xl border-2 border-dashed border-gray-200 flex flex-col items-center justify-center text-gray-400">
            <Users size={64} className="mb-4 opacity-20" />
            <p className="text-lg font-medium">Nenhum membro encontrado.</p>
            <p className="text-sm">Tente ajustar seus filtros ou busca.</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default MemberList;

export enum MemberCategory {
  CHILD = 'Criança',
  YOUTH = 'Jovem',
  ADULT = 'Adulto',
  ELDER = 'Idoso'
}

export enum Gender {
  MALE = 'Masculino',
  FEMALE = 'Feminino'
}

export interface Member {
  id: string;
  name: string;
  birthDate: string;
  category: MemberCategory;
  gender: Gender;
  phone: string;
  address: string;
  baptismDate?: string;
  department?: string;
  photoUrl?: string;
  createdAt: string;
}

export type ViewType = 'dashboard' | 'members' | 'register' | 'birthdays' | 'ai-assistant' | 'id-card';

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Users, 
  UserPlus, 
  LayoutDashboard, 
  Gift, 
  Menu, 
  X, 
  Church,
  Sparkles,
  Contact
} from 'lucide-react';
import { Member, MemberCategory, ViewType } from './types';
import Dashboard from './components/Dashboard';
import MemberList from './components/MemberList';
import MemberForm from './components/MemberForm';
import BirthdayList from './components/BirthdayList';
import AIAssistant from './components/AIAssistant';
import IDCardGenerator from './components/IDCardGenerator';
import { CHURCH_NAME } from './constants';

const App: React.FC = () => {
  const [members, setMembers] = useState<Member[]>([]);
  const [currentView, setCurrentView] = useState<ViewType>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [editingMember, setEditingMember] = useState<Member | null>(null);

  // Persistence
  useEffect(() => {
    const saved = localStorage.getItem('ad_aguiarnopolis_members');
    if (saved) {
      try {
        setMembers(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to load members", e);
      }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('ad_aguiarnopolis_members', JSON.stringify(members));
  }, [members]);

  const addMember = (newMember: Member) => {
    setMembers(prev => [...prev, newMember]);
    setCurrentView('members');
  };

  const updateMember = (updated: Member) => {
    setMembers(prev => prev.map(m => m.id === updated.id ? updated : m));
    setEditingMember(null);
    setCurrentView('members');
  };

  const deleteMember = (id: string) => {
    if (confirm('Tem certeza que deseja excluir este membro?')) {
      setMembers(prev => prev.filter(m => m.id !== id));
    }
  };

  const handleEdit = (member: Member) => {
    setEditingMember(member);
    setCurrentView('register');
  };

  const NavItem = ({ view, icon: Icon, label }: { view: ViewType, icon: any, label: string }) => (
    <button
      onClick={() => {
        setCurrentView(view);
        setEditingMember(null);
        setIsSidebarOpen(false);
      }}
      className={`flex items-center space-x-3 w-full px-4 py-3 rounded-lg transition-colors ${
        currentView === view 
          ? 'bg-blue-600 text-white shadow-md' 
          : 'text-gray-600 hover:bg-blue-50 hover:text-blue-600'
      }`}
    >
      <Icon size={20} />
      <span className="font-medium">{label}</span>
    </button>
  );

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-gray-50">
      {/* Mobile Header */}
      <header className="md:hidden bg-blue-900 text-white p-4 flex justify-between items-center sticky top-0 z-50 shadow-md">
        <div className="flex items-center space-x-2">
          <Church size={24} className="text-amber-400" />
          <h1 className="text-lg font-bold truncate">AD Aguiarnópolis</h1>
        </div>
        <button onClick={() => setIsSidebarOpen(!isSidebarOpen)}>
          {isSidebarOpen ? <X size={28} /> : <Menu size={28} />}
        </button>
      </header>

      {/* Sidebar Overlay */}
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black bg-opacity-50 z-40 md:hidden"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      {/* Sidebar */}
      <aside className={`
        fixed inset-y-0 left-0 transform ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
        md:relative md:translate-x-0 transition duration-200 ease-in-out
        z-50 w-64 bg-white border-r border-gray-200 flex flex-col h-full
      `}>
        <div className="p-6 border-b border-gray-100 hidden md:block">
          <div className="flex items-center space-x-2 mb-2">
            <Church size={32} className="text-blue-700" />
            <span className="text-blue-900 font-bold text-xl leading-tight">AD Aguiarnópolis</span>
          </div>
          <p className="text-xs text-gray-400 uppercase tracking-widest font-semibold">Gestão de Membros</p>
        </div>

        <nav className="flex-1 px-4 py-6 space-y-2">
          <NavItem view="dashboard" icon={LayoutDashboard} label="Dashboard" />
          <NavItem view="members" icon={Users} label="Membros" />
          <NavItem view="register" icon={UserPlus} label={editingMember ? "Editar Membro" : "Novo Membro"} />
          <NavItem view="birthdays" icon={Gift} label="Aniversariantes" />
          <NavItem view="id-card" icon={Contact} label="Carteira Membro" />
          <NavItem view="ai-assistant" icon={Sparkles} label="Assistente IA" />
        </nav>

        <div className="p-4 border-t border-gray-100">
          <div className="bg-blue-50 p-4 rounded-xl">
            <p className="text-xs text-blue-800 font-medium">Total de Membros</p>
            <p className="text-2xl font-bold text-blue-900">{members.length}</p>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto p-4 md:p-8">
        <div className="max-w-6xl mx-auto">
          {currentView === 'dashboard' && <Dashboard members={members} onNavigate={setCurrentView} />}
          {currentView === 'members' && (
            <MemberList 
              members={members} 
              onDelete={deleteMember} 
              onEdit={handleEdit} 
            />
          )}
          {currentView === 'register' && (
            <MemberForm 
              onSave={editingMember ? updateMember : addMember} 
              initialData={editingMember} 
              onCancel={() => {
                setEditingMember(null);
                setCurrentView('members');
              }}
            />
          )}
          {currentView === 'birthdays' && <BirthdayList members={members} />}
          {currentView === 'id-card' && <IDCardGenerator members={members} />}
          {currentView === 'ai-assistant' && <AIAssistant members={members} />}
        </div>
      </main>
    </div>
  );
};

export default App;

