import React, { useState, useEffect } from 'react';
import { 
  Users, 
  UserPlus, 
  LayoutDashboard, 
  Gift, 
  Menu, 
  X, 
  Church,
  Sparkles,
  Contact
} from 'lucide-react';
import { Member, ViewType } from './types';
import Dashboard from './components/Dashboard';
import MemberList from './components/MemberList';
import MemberForm from './components/MemberForm';
import BirthdayList from './components/BirthdayList';
import AIAssistant from './components/AIAssistant';
import IDCardGenerator from './components/IDCardGenerator';

const App: React.FC = () => {
  const [members, setMembers] = useState<Member[]>([]);
  const [currentView, setCurrentView] = useState<ViewType>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [editingMember, setEditingMember] = useState<Member | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem('ad_aguiarnopolis_members');
    if (saved) {
      try {
        setMembers(JSON.parse(saved));
      } catch (e) {
        console.error("Falha ao carregar membros", e);
      }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('ad_aguiarnopolis_members', JSON.stringify(members));
  }, [members]);

  const addMember = (newMember: Member) => {
    setMembers(prev => [...prev, newMember]);
    setCurrentView('members');
  };

  const updateMember = (updated: Member) => {
    setMembers(prev => prev.map(m => m.id === updated.id ? updated : m));
    setEditingMember(null);
    setCurrentView('members');
  };

  const deleteMember = (id: string) => {
    if (confirm('Tem certeza que deseja excluir este membro?')) {
      setMembers(prev => prev.filter(m => m.id !== id));
    }
  };

  const handleEdit = (member: Member) => {
    setEditingMember(member);
    setCurrentView('register');
  };

  const NavItem = ({ view, icon: Icon, label }: { view: ViewType, icon: React.ElementType, label: string }) => (
    <button
      onClick={() => {
        setCurrentView(view);
        setEditingMember(null);
        setIsSidebarOpen(false);
      }}
      className={`flex items-center space-x-3 w-full px-4 py-3 rounded-lg transition-all duration-200 ${
        currentView === view 
          ? 'bg-blue-600 text-white shadow-lg scale-105' 
          : 'text-gray-600 hover:bg-blue-50 hover:text-blue-600'
      }`}
      aria-label={label}
    >
      <Icon size={20} />
      <span className="font-medium">{label}</span>
    </button>
  );

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-gray-50">
      <header className="md:hidden bg-blue-900 text-white p-4 flex justify-between items-center sticky top-0 z-50 shadow-md no-print">
        <div className="flex items-center space-x-2">
          <Church size={24} className="text-amber-400" />
          <h1 className="text-lg font-bold truncate">AD Aguiarnópolis</h1>
        </div>
        <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-1">
          {isSidebarOpen ? <X size={28} /> : <Menu size={28} />}
        </button>
      </header>

      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/50 z-40 md:hidden backdrop-blur-sm"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      <aside className={`
        fixed inset-y-0 left-0 transform ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
        md:relative md:translate-x-0 transition-transform duration-300 ease-in-out
        z-50 w-64 bg-white border-r border-gray-200 flex flex-col h-screen no-print
      `}>
        <div className="p-6 border-b border-gray-100 hidden md:block">
          <div className="flex items-center space-x-2 mb-2">
            <Church size={32} className="text-blue-700" />
            <span className="text-blue-900 font-extrabold text-xl leading-tight">AD Aguiarnópolis</span>
          </div>
          <p className="text-[10px] text-gray-400 uppercase tracking-[0.2em] font-bold">Gestão de Membros</p>
        </div>

        <nav className="flex-1 px-4 py-6 space-y-2 overflow-y-auto">
          <NavItem view="dashboard" icon={LayoutDashboard} label="Dashboard" />
          <NavItem view="members" icon={Users} label="Membros" />
          <NavItem view="register" icon={UserPlus} label={editingMember ? "Editar Membro" : "Novo Membro"} />
          <NavItem view="birthdays" icon={Gift} label="Aniversariantes" />
          <NavItem view="id-card" icon={Contact} label="Carteira Membro" />
          <NavItem view="ai-assistant" icon={Sparkles} label="Assistente IA" />
        </nav>

        <div className="p-4 border-t border-gray-100">
          <div className="bg-blue-50 p-4 rounded-2xl">
            <p className="text-xs text-blue-800 font-semibold mb-1">Total Congregação</p>
            <p className="text-2xl font-black text-blue-900">{members.length}</p>
          </div>
        </div>
      </aside>

      <main className="flex-1 overflow-y-auto p-4 md:p-8">
        <div className="max-w-6xl mx-auto">
          {currentView === 'dashboard' && <Dashboard members={members} onNavigate={setCurrentView} />}
          {currentView === 'members' && (
            <MemberList 
              members={members} 
              onDelete={deleteMember} 
              onEdit={handleEdit} 
            />
          )}
          {currentView === 'register' && (
            <MemberForm 
              key={editingMember?.id || 'new'}
              onSave={editingMember ? updateMember : addMember} 
              initialData={editingMember} 
              onCancel={() => {
                setEditingMember(null);
                setCurrentView('members');
              }}
            />
          )}
          {currentView === 'birthdays' && <BirthdayList members={members} />}
          {currentView === 'id-card' && <IDCardGenerator members={members} />}
          {currentView === 'ai-assistant' && <AIAssistant members={members} />}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Member, MemberCategory, Gender } from '../types';
import { Camera, Save, ArrowLeft, Calendar, User, Phone, Home, MapPin, TrendingUp } from 'lucide-react';
import { DEPARTMENTS } from '../constants';

interface MemberFormProps {
  onSave: (member: Member) => void;
  initialData?: Member | null;
  onCancel: () => void;
}

const MemberForm: React.FC<MemberFormProps> = ({ onSave, initialData, onCancel }) => {
  const [formData, setFormData] = useState<Partial<Member>>({
    name: '',
    birthDate: '',
    category: MemberCategory.ADULT,
    gender: Gender.MALE,
    phone: '',
    address: '',
    department: DEPARTMENTS[0],
    ...(initialData || {})
  });

  const [photoPreview, setPhotoPreview] = useState<string | undefined>(initialData?.photoUrl);

  const handlePhotoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 1024 * 1024) { // 1MB Limit
        alert("A imagem é muito grande. Escolha uma foto menor que 1MB.");
        return;
      }
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64 = reader.result as string;
        setPhotoPreview(base64);
        setFormData(prev => ({ ...prev, photoUrl: base64 }));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.birthDate) {
      alert('Por favor, preencha o nome e a data de nascimento.');
      return;
    }

    const member: Member = {
      id: initialData?.id || Date.now().toString(),
      name: formData.name || '',
      birthDate: formData.birthDate || '',
      category: formData.category || MemberCategory.ADULT,
      gender: formData.gender || Gender.MALE,
      phone: formData.phone || '',
      address: formData.address || '',
      baptismDate: formData.baptismDate,
      department: formData.department,
      photoUrl: formData.photoUrl,
      createdAt: initialData?.createdAt || new Date().toISOString(),
    };

    onSave(member);
  };

  const calculateCategory = (birthDate: string) => {
    if (!birthDate) return MemberCategory.ADULT;
    const age = Math.floor((new Date().getTime() - new Date(birthDate).getTime()) / 31557600000);
    if (age < 12) return MemberCategory.CHILD;
    if (age < 18) return MemberCategory.YOUTH;
    if (age > 60) return MemberCategory.ELDER;
    return MemberCategory.ADULT;
  };

  const InputField = ({ label, icon: Icon, children }: any) => (
    <div className="space-y-1">
      <label className="text-sm font-bold text-gray-700 block ml-1">{label}</label>
      <div className="relative">
        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
          <Icon size={18} />
        </div>
        {children}
      </div>
    </div>
  );

  return (
    <div className="bg-white rounded-3xl shadow-xl overflow-hidden max-w-4xl mx-auto border border-gray-100 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="bg-blue-700 p-6 md:p-10 text-white flex justify-between items-center">
        <div>
          <h2 className="text-2xl md:text-3xl font-black">{initialData ? 'Editar Registro' : 'Cadastro de Membro'}</h2>
          <p className="text-blue-100 mt-1 opacity-80">Gerencie as informações da congregação em Aguiarnópolis.</p>
        </div>
        <button 
          onClick={onCancel}
          className="bg-white/10 hover:bg-white/20 p-3 rounded-2xl transition-all duration-200"
          type="button"
        >
          <ArrowLeft size={24} />
        </button>
      </div>

      <form onSubmit={handleSubmit} className="p-6 md:p-10 space-y-8">
        <div className="flex flex-col md:flex-row gap-10">
          <div className="flex flex-col items-center space-y-4">
            <div className="w-44 h-44 rounded-3xl bg-gray-50 border-4 border-white shadow-xl overflow-hidden relative group transition-transform hover:scale-105">
              {photoPreview ? (
                <img src={photoPreview} alt="Preview" className="w-full h-full object-cover" />
              ) : (
                <div className="w-full h-full flex flex-col items-center justify-center text-gray-300">
                  <User size={64} strokeWidth={1} />
                  <span className="text-[10px] font-bold uppercase mt-2 tracking-widest">Sem Foto</span>
                </div>
              )}
              <label className="absolute inset-0 bg-blue-900/60 flex items-center justify-center opacity-0 group-hover:opacity-100 cursor-pointer transition-opacity duration-300">
                <div className="text-white flex flex-col items-center">
                  <Camera size={32} />
                  <span className="text-[10px] font-bold mt-1 uppercase">Trocar</span>
                </div>
                <input type="file" className="hidden" accept="image/*" onChange={handlePhotoChange} />
              </label>
            </div>
            <p className="text-[10px] text-gray-400 text-center max-w-[160px] font-medium uppercase tracking-tighter">Use uma foto clara estilo 3x4 (máx 1MB).</p>
          </div>

          <div className="flex-1 grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="md:col-span-2">
              <InputField label="Nome Completo" icon={User}>
                <input
                  type="text"
                  required
                  value={formData.name}
                  onChange={e => setFormData({ ...formData, name: e.target.value })}
                  className="w-full pl-10 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 outline-none transition-all"
                  placeholder="Nome do membro"
                />
              </InputField>
            </div>

            <InputField label="Data de Nascimento" icon={Calendar}>
              <input
                type="date"
                required
                value={formData.birthDate}
                onChange={e => {
                  const val = e.target.value;
                  setFormData({ 
                    ...formData, 
                    birthDate: val,
                    category: calculateCategory(val)
                  });
                }}
                className="w-full pl-10 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 outline-none transition-all"
              />
            </InputField>

            <InputField label="Categoria (Automática)" icon={TrendingUp}>
              <select
                value={formData.category}
                onChange={e => setFormData({ ...formData, category: e.target.value as MemberCategory })}
                className="w-full pl-10 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 outline-none appearance-none transition-all"
              >
                {Object.values(MemberCategory).map(cat => (
                  <option key={cat} value={cat}>{cat}</option>
                ))}
              </select>
            </InputField>

            <InputField label="Gênero" icon={User}>
              <select
                value={formData.gender}
                onChange={e => setFormData({ ...formData, gender: e.target.value as Gender })}
                className="w-full pl-10 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 outline-none appearance-none transition-all"
              >
                <option value={Gender.MALE}>Masculino</option>
                <option value={Gender.FEMALE}>Feminino</option>
              </select>
            </InputField>

            <InputField label="WhatsApp / Telefone" icon={Phone}>
              <input
                type="tel"
                value={formData.phone}
                onChange={e => setFormData({ ...formData, phone: e.target.value })}
                className="w-full pl-10 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 outline-none transition-all"
                placeholder="(63) 90000-0000"
              />
            </InputField>

            <div className="md:col-span-2">
              <InputField label="Endereço" icon={MapPin}>
                <input
                  type="text"
                  value={formData.address}
                  onChange={e => setFormData({ ...formData, address: e.target.value })}
                  className="w-full pl-10 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 outline-none transition-all"
                  placeholder="Rua, Bairro, Número"
                />
              </InputField>
            </div>

            <InputField label="Data de Batismo" icon={Calendar}>
              <input
                type="date"
                value={formData.baptismDate}
                onChange={e => setFormData({ ...formData, baptismDate: e.target.value })}
                className="w-full pl-10 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 outline-none transition-all"
              />
            </InputField>

            <InputField label="Departamento Principal" icon={Home}>
              <select
                value={formData.department}
                onChange={e => setFormData({ ...formData, department: e.target.value })}
                className="w-full pl-10 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 outline-none appearance-none transition-all"
              >
                <option value="">Nenhum / Membro Geral</option>
                {DEPARTMENTS.map(dept => (
                  <option key={dept} value={dept}>{dept}</option>
                ))}
              </select>
            </InputField>
          </div>
        </div>

        <div className="flex justify-end space-x-4 pt-6 border-t border-gray-100">
          <button
            type="button"
            onClick={onCancel}
            className="px-8 py-4 bg-gray-100 text-gray-700 rounded-2xl font-bold hover:bg-gray-200 transition-all duration-200"
          >
            Cancelar
          </button>
          <button
            type="submit"
            className="px-10 py-4 bg-blue-700 text-white rounded-2xl font-black hover:bg-blue-800 transition-all duration-200 shadow-xl shadow-blue-500/20 flex items-center space-x-2 active:scale-95"
          >
            <Save size={20} />
            <span>{initialData ? 'Atualizar Membro' : 'Salvar Cadastro'}</span>
          </button>
        </div>
      </form>
    </div>
  );
};

export default MemberForm;

import React, { useState } from 'react';
import { GoogleGenAI } from "@google/genai";
import { Member } from '../types';
import { Sparkles, MessageSquare, BookOpen, Loader2, User, Church, Copy, Check } from 'lucide-react';

interface AIAssistantProps {
  members: Member[];
}

const AIAssistant: React.FC<AIAssistantProps> = ({ members }) => {
  const [selectedMemberId, setSelectedMemberId] = useState('');
  const [loading, setLoading] = useState(false);
  const [response, setResponse] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);

  const generateSpiritualInsight = async (type: 'prayer' | 'devotional') => {
    if (!selectedMemberId) {
      alert('Selecione um membro primeiro.');
      return;
    }

    const member = members.find(m => m.id === selectedMemberId);
    if (!member) return;

    setLoading(true);
    setError(null);
    setResponse(null);
    setCopied(false);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const promptText = type === 'prayer' 
        ? `Escreva um pequeno texto de oração e encorajamento personalizado para um membro da igreja chamado ${member.name}, que é da categoria ${member.category}. Use uma linguagem cristã acolhedora da Assembleia de Deus e cite um versículo bíblico apropriado.`
        : `Como líder da igreja Assembleia de Deus, escreva uma breve mensagem devocional para o irmão(a) ${member.name} (Categoria: ${member.category}). Fale sobre o valor da sua presença na congregação em Aguiarnópolis e deseje bênçãos sobre sua vida.`;

      const result = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: promptText,
      });

      setResponse(result.text || 'Não foi possível gerar a mensagem.');
    } catch (err: any) {
      console.error(err);
      setError(`Erro ao consultar a IA: ${err.message || 'Erro desconhecido'}. Verifique sua conexão ou tente mais tarde.`);
    } finally {
      setLoading(false);
    }
  };

  const copyToClipboard = () => {
    if (response) {
      navigator.clipboard.writeText(response);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  return (
    <div className="max-w-3xl mx-auto space-y-8 pb-10">
      <header className="text-center space-y-3">
        <div className="inline-flex p-5 bg-blue-100 text-blue-700 rounded-[2rem] shadow-inner mb-2 animate-bounce">
          <Sparkles size={40} />
        </div>
        <h2 className="text-4xl font-black text-gray-900 tracking-tight">Assistente Espiritual IA</h2>
        <p className="text-gray-500 max-w-md mx-auto leading-relaxed">Mensagens de fé e devocionais personalizados para fortalecer a comunhão da igreja.</p>
      </header>

      <div className="bg-white rounded-3xl p-8 shadow-2xl shadow-blue-900/5 border border-gray-100 space-y-6">
        <div className="space-y-4">
          <label className="text-sm font-black text-gray-700 block ml-1 uppercase tracking-wider">Membro Beneficiado</label>
          <div className="relative">
            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
              <User size={20} />
            </div>
            <select
              value={selectedMemberId}
              onChange={e => setSelectedMemberId(e.target.value)}
              className="w-full pl-10 pr-10 py-4 bg-gray-50 border border-gray-200 rounded-2xl focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 outline-none appearance-none cursor-pointer transition-all font-medium"
            >
              <option value="">Selecione um irmão na lista...</option>
              {members.length === 0 && <option disabled>Nenhum membro cadastrado</option>}
              {members.map(m => (
                <option key={m.id} value={m.id}>{m.name} • {m.category}</option>
              ))}
            </select>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <button
            onClick={() => generateSpiritualInsight('prayer')}
            disabled={loading || !selectedMemberId}
            className="flex items-center justify-center space-x-3 p-5 bg-blue-700 text-white rounded-2xl font-black hover:bg-blue-800 transition-all disabled:opacity-50 shadow-xl shadow-blue-500/20 active:scale-95"
          >
