import React, { useState } from 'react';
import { GoogleGenAI } from "@google/genai";
import { Member } from '../types';
// Fixed: Added 'X' to the imports from lucide-react to resolve the reference error on line 114
import { Sparkles, MessageSquare, BookOpen, Loader2, User, Church, Copy, Check, X } from 'lucide-react';

interface AIAssistantProps {
  members: Member[];
}

const AIAssistant: React.FC<AIAssistantProps> = ({ members }) => {
  const [selectedMemberId, setSelectedMemberId] = useState('');
  const [loading, setLoading] = useState(false);
  const [response, setResponse] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);

  const generateSpiritualInsight = async (type: 'prayer' | 'devotional') => {
    if (!selectedMemberId) {
      alert('Selecione um membro primeiro.');
      return;
    }

    const member = members.find(m => m.id === selectedMemberId);
    if (!member) return;

    setLoading(true);
    setError(null);
    setResponse(null);
    setCopied(false);

    try {
      // Correct initialization using named parameter for apiKey as per @google/genai guidelines
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const promptText = type === 'prayer' 
        ? `Escreva um pequeno texto de oração e encorajamento personalizado para um membro da igreja chamado ${member.name}, que é da categoria ${member.category}. Use uma linguagem cristã acolhedora da Assembleia de Deus e cite um versículo bíblico apropriado.`
        : `Como líder da igreja Assembleia de Deus, escreva uma breve mensagem devocional para o irmão(a) ${member.name} (Categoria: ${member.category}). Fale sobre o valor da sua presença na congregação em Aguiarnópolis e deseje bênçãos sobre sua vida.`;

      const result = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: promptText,
      });

      // result.text is a property, not a method, as per SDK guidelines
      setResponse(result.text || 'Não foi possível gerar a mensagem.');
    } catch (err: any) {
      console.error(err);
      setError(`Erro ao consultar a IA: ${err.message || 'Erro desconhecido'}. Verifique sua conexão ou tente mais tarde.`);
    } finally {
      setLoading(false);
    }
  };

  const copyToClipboard = () => {
    if (response) {
      navigator.clipboard.writeText(response);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  return (
    <div className="max-w-3xl mx-auto space-y-8 pb-10">
      <header className="text-center space-y-3">
        <div className="inline-flex p-5 bg-blue-100 text-blue-700 rounded-[2rem] shadow-inner mb-2 animate-bounce">
          <Sparkles size={40} />
        </div>
        <h2 className="text-4xl font-black text-gray-900 tracking-tight">Assistente Espiritual IA</h2>
        <p className="text-gray-500 max-w-md mx-auto leading-relaxed">Mensagens de fé e devocionais personalizados para fortalecer a comunhão da igreja.</p>
      </header>

      <div className="bg-white rounded-3xl p-8 shadow-2xl shadow-blue-900/5 border border-gray-100 space-y-6">
        <div className="space-y-4">
          <label className="text-sm font-black text-gray-700 block ml-1 uppercase tracking-wider">Membro Beneficiado</label>
          <div className="relative">
            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
              <User size={20} />
            </div>
            <select
              value={selectedMemberId}
              onChange={e => setSelectedMemberId(e.target.value)}
              className="w-full pl-10 pr-10 py-4 bg-gray-50 border border-gray-200 rounded-2xl focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 outline-none appearance-none cursor-pointer transition-all font-medium"
            >
              <option value="">Selecione um irmão na lista...</option>
              {members.length === 0 && <option disabled>Nenhum membro cadastrado</option>}
              {members.map(m => (
                <option key={m.id} value={m.id}>{m.name} • {m.category}</option>
              ))}
            </select>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <button
            onClick={() => generateSpiritualInsight('prayer')}
            disabled={loading || !selectedMemberId}
            className="flex items-center justify-center space-x-3 p-5 bg-blue-700 text-white rounded-2xl font-black hover:bg-blue-800 transition-all disabled:opacity-50 shadow-xl shadow-blue-500/20 active:scale-95"
          >
            {loading ? <Loader2 size={24} className="animate-spin" /> : <MessageSquare size={24} />}
            <span>Gerar Oração</span>
          </button>

          <button
            onClick={() => generateSpiritualInsight('devotional')}
            disabled={loading || !selectedMemberId}
            className="flex items-center justify-center space-x-3 p-5 bg-amber-600 text-white rounded-2xl font-black hover:bg-amber-700 transition-all disabled:opacity-50 shadow-xl shadow-amber-500/20 active:scale-95"
          >
            {loading ? <Loader2 size={24} className="animate-spin" /> : <BookOpen size={24} />}
            <span>Mensagem Devocional</span>
          </button>
        </div>
      </div>

      {error && (
        <div className="bg-red-50 text-red-700 p-6 rounded-3xl border border-red-100 flex items-start space-x-3">
          <div className="shrink-0 p-1 bg-red-100 rounded-full mt-0.5"><X size={14} /></div>
          <p className="text-sm font-medium">{error}</p>
        </div>
      )}

      {response && (
        <div className="bg-white rounded-3xl p-8 shadow-2xl border-2 border-blue-50 relative overflow-hidden animate-in fade-in zoom-in duration-500">
          <div className="absolute top-0 right-0 p-6 opacity-[0.03] pointer-events-none">
            <Church size={150} />
          </div>
          <div className="relative z-10 prose prose-blue max-w-none">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-blue-900 font-black text-2xl flex items-center m-0">
                <Sparkles className="mr-3 text-amber-400" size={28} />
                Palavra Inspirada
              </h3>
              <button 
                onClick={copyToClipboard}
                className={`p-3 rounded-2xl transition-all flex items-center space-x-2 text-xs font-bold uppercase tracking-widest ${
                  copied ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-500 hover:bg-gray-200'
                }`}
              >
                {copied ? <Check size={16} /> : <Copy size={16} />}
                <span>{copied ? 'Copiado!' : 'Copiar'}</span>
              </button>
            </div>
            <div className="p-6 bg-blue-50/50 rounded-[2rem] border border-blue-100/50">
              <div className="whitespace-pre-wrap text-gray-800 leading-relaxed italic font-serif text-lg">
                "{response}"
              </div>
            </div>
            <div className="mt-8 pt-6 border-t border-gray-100 flex flex-col sm:flex-row justify-between items-center text-[10px] text-gray-400 font-bold uppercase tracking-widest">
              <span>Gerado pela Inteligência Artificial da AD Aguiarnópolis</span>
              <span className="mt-2 sm:mt-0 opacity-60">"Onde houver dois ou três reunidos..."</span>
            </div>
          </div>
        </div>
      )}
    </div>
  );
