import React, { useState } from 'react';
import { Member, MemberCategory, Gender, CivilStatus } from '../types';
import { 
  Camera, Save, ArrowLeft, Calendar, User, Phone, Home, 
  MapPin, TrendingUp, Briefcase, Globe, Heart, Users 
} from 'lucide-react';
import { DEPARTMENTS } from '../constants';

interface MemberFormProps {
  onSave: (member: Member) => void;
  initialData?: Member | null;
  onCancel: () => void;
}

const MemberForm: React.FC<MemberFormProps> = ({ onSave, initialData, onCancel }) => {
  const [formData, setFormData] = useState<Partial<Member>>({
    name: '',
    birthDate: '',
    category: MemberCategory.ADULT,
    gender: Gender.MALE,
    civilStatus: CivilStatus.SINGLE,
    phone: '',
    address: '',
    department: DEPARTMENTS[0],
    ...(initialData || {})
  });

  const [photoPreview, setPhotoPreview] = useState<string | undefined>(initialData?.photoUrl);

  const handlePhotoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 1024 * 1024) {
        alert("A imagem é muito grande. Escolha uma foto menor que 1MB.");
        return;
      }
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64 = reader.result as string;
        setPhotoPreview(base64);
        setFormData(prev => ({ ...prev, photoUrl: base64 }));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.birthDate) {
      alert('Por favor, preencha o nome e a data de nascimento.');
      return;
    }

    const member: Member = {
      id: initialData?.id || Date.now().toString(),
      name: formData.name || '',
      birthDate: formData.birthDate || '',
      category: formData.category || MemberCategory.ADULT,
      gender: formData.gender || Gender.MALE,
      civilStatus: formData.civilStatus || CivilStatus.SINGLE,
      profession: formData.profession,
      nationality: formData.nationality,
      naturalness: formData.naturalness,
      fatherName: formData.fatherName,
      motherName: formData.motherName,
      phone: formData.phone || '',
      address: formData.address || '',
      baptismDate: formData.baptismDate,
      department: formData.department,
      photoUrl: formData.photoUrl,
      createdAt: initialData?.createdAt || new Date().toISOString(),
    };

    onSave(member);
  };

  const calculateCategory = (birthDate: string) => {
    if (!birthDate) return MemberCategory.ADULT;
    const age = Math.floor((new Date().getTime() - new Date(birthDate).getTime()) / 31557600000);
    if (age < 12) return MemberCategory.CHILD;
    if (age < 18) return MemberCategory.YOUTH;
    if (age > 60) return MemberCategory.ELDER;
    return MemberCategory.ADULT;
  };

  const InputField = ({ label, icon: Icon, children, className = "" }: any) => (
    <div className={`space-y-1 ${className}`}>
      <label className="text-xs font-black text-gray-500 uppercase tracking-wider block ml-1">{label}</label>
      <div className="relative">
        {Icon && (
          <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
            <Icon size={18} />
          </div>
        )}
        {children}
      </div>
    </div>
  );

  const SectionTitle = ({ icon: Icon, title }: any) => (
    <div className="flex items-center space-x-2 border-b border-gray-100 pb-2 mb-6">
      <div className="p-2 bg-blue-50 text-blue-600 rounded-lg">
        <Icon size={20} />
      </div>
      <h3 className="text-lg font-bold text-gray-800">{title}</h3>
    </div>
  );

  return (
    <div className="bg-white rounded-3xl shadow-xl overflow-hidden max-w-5xl mx-auto border border-gray-100 mb-10">
      <div className="bg-blue-800 p-8 text-white flex justify-between items-center">
        <div>
          <h2 className="text-3xl font-black">{initialData ? 'Editar Prontuário' : 'Novo Cadastro de Membro'}</h2>
          <p className="text-blue-100 mt-1 opacity-80">Assembleia de Deus em Aguiarnópolis - Sistema COMADESMA</p>
        </div>
        <button onClick={onCancel} className="bg-white/10 hover:bg-white/20 p-3 rounded-2xl transition-all" type="button">
          <ArrowLeft size={24} />
        </button>
      </div>

      <form onSubmit={handleSubmit} className="p-8 space-y-12">
        <div className="flex flex-col lg:flex-row gap-12">
          {/* Lado Esquerdo: Foto e Status Rápido */}
          <div className="flex flex-col items-center space-y-6 lg:w-1/4">
            <div className="w-48 h-56 rounded-[2.5rem] bg-gray-50 border-4 border-white shadow-2xl overflow-hidden relative group transition-transform hover:scale-105">
              {photoPreview ? (
                <img src={photoPreview} alt="Preview" className="w-full h-full object-cover" />
              ) : (
                <div className="w-full h-full flex flex-col items-center justify-center text-gray-300">
                  <User size={80} strokeWidth={1} />
                  <span className="text-[10px] font-bold uppercase mt-2 tracking-widest">Sem Foto</span>
                </div>
              )}
              <label className="absolute inset-0 bg-blue-900/60 flex items-center justify-center opacity-0 group-hover:opacity-100 cursor-pointer transition-opacity duration-300">
                <div className="text-white flex flex-col items-center">
                  <Camera size={32} />
                  <span className="text-[10px] font-bold mt-1 uppercase">Alterar</span>
                </div>
                <input type="file" className="hidden" accept="image/*" onChange={handlePhotoChange} />
              </label>
            </div>

            <div className="w-full space-y-4">
              <InputField label="Categoria" icon={TrendingUp}>
                <select
                  value={formData.category}
                  onChange={e => setFormData({ ...formData, category: e.target.value as MemberCategory })}
                  className="w-full pl-10 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-4 focus:ring-blue-500/10 outline-none appearance-none font-bold text-blue-700"
                >
                  {Object.values(MemberCategory).map(cat => <option key={cat} value={cat}>{cat}</option>)}
                </select>
              </InputField>
            </div>
          </div>

          {/* Lado Direito: Seções do Formulário */}
          <div className="flex-1 space-y-10">
            {/* Seção 1: Dados Pessoais */}
            <section>
              <SectionTitle icon={User} title="Dados Pessoais" />
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <InputField label="Nome Completo" icon={User} className="md:col-span-2">
                  <input
                    type="text" required value={formData.name}
                    onChange={e => setFormData({ ...formData, name: e.target.value })}
                    className="w-full pl-10 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-4 focus:ring-blue-500/10 outline-none"
                    placeholder="Nome completo do membro"
                  />
                </InputField>

                <InputField label="Data de Nascimento" icon={Calendar}>
                  <input
                    type="date" required value={formData.birthDate}
                    onChange={e => {
                      const val = e.target.value;
                      setFormData({ ...formData, birthDate: val, category: calculateCategory(val) });
                    }}
                    className="w-full pl-10 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-4 focus:ring-blue-500/10 outline-none"
                  />
                </InputField>

                <InputField label="Gênero" icon={User}>
                  <select
                    value={formData.gender}
                    onChange={e => setFormData({ ...formData, gender: e.target.value as Gender })}
                    className="w-full pl-10 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-4 focus:ring-blue-500/10 outline-none appearance-none"
                  >
                    <option value={Gender.MALE}>Masculino</option>
                    <option value={Gender.FEMALE}>Feminino</option>
                  </select>
                </InputField>

                <InputField label="Estado Civil" icon={Heart}>
                  <select
                    value={formData.civilStatus}
                    onChange={e => setFormData({ ...formData, civilStatus: e.target.value as CivilStatus })}
                    className="w-full pl-10 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-4 focus:ring-blue-500/10 outline-none appearance-none"
                  >
                    {Object.values(CivilStatus).map(status => <option key={status} value={status}>{status}</option>)}
                  </select>
                </InputField>

                <InputField label="Profissão" icon={Briefcase}>
                  <input
                    type="text" value={formData.profession || ''}
                    onChange={e => setFormData({ ...formData, profession: e.target.value })}
                    className="w-full pl-10 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-4 focus:ring-blue-500/10 outline-none"
                    placeholder="Ex: Professor, Pedreiro..."
                  />
                </InputField>

                <InputField label="Naturalidade" icon={MapPin}>
                  <input
                    type="text" value={formData.naturalness || ''}
                    onChange={e => setFormData({ ...formData, naturalness: e.target.value })}
                    className="w-full pl-10 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-4 focus:ring-blue-500/10 outline-none"
                    placeholder="Cidade de nascimento"
                  />
                </InputField>

                <InputField label="Nacionalidade" icon={Globe}>
                  <input
                    type="text" value={formData.nationality || ''}
                    onChange={e => setFormData({ ...formData, nationality: e.target.value })}
                    className="w-full pl-10 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-4 focus:ring-blue-500/10 outline-none"
                    placeholder="Ex: Brasileira"
                  />
                </InputField>

                <InputField label="WhatsApp / Telefone" icon={Phone}>
                  <input
                    type="tel" value={formData.phone}
                    onChange={e => setFormData({ ...formData, phone: e.target.value })}
                    className="w-full pl-10 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-4 focus:ring-blue-500/10 outline-none"
                    placeholder="(63) 90000-0000"
                  />
                </InputField>

                <InputField label="Endereço Residencial" icon={Home} className="md:col-span-2">
                  <input
                    type="text" value={formData.address}
                    onChange={e => setFormData({ ...formData, address: e.target.value })}
                    className="w-full pl-10 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-4 focus:ring-blue-500/10 outline-none"
                    placeholder="Rua, Número, Bairro, Aguiarnópolis-TO"
                  />
                </InputField>
              </div>
            </section>

            {/* Seção 2: Dados Familiares */}
            <section>
              <SectionTitle icon={Users} title="Dados Familiares" />
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <InputField label="Nome do Pai" icon={User}>
                  <input
                    type="text" value={formData.fatherName || ''}
                    onChange={e => setFormData({ ...formData, fatherName: e.target.value })}
                    className="w-full pl-10 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-4 focus:ring-blue-500/10 outline-none"
                  />
                </InputField>
                <InputField label="Nome da Mãe" icon={User}>
                  <input
                    type="text" value={formData.motherName || ''}
                    onChange={e => setFormData({ ...formData, motherName: e.target.value })}
                    className="w-full pl-10 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-4 focus:ring-blue-500/10 outline-none"
                  />
                </InputField>
              </div>
            </section>

            {/* Seção 3: Dados Eclesiásticos */}
            <section>
              <SectionTitle icon={Home} title="Dados Eclesiásticos" />
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <InputField label="Data de Batismo nas Águas" icon={Calendar}>
                  <input
                    type="date" value={formData.baptismDate || ''}
                    onChange={e => setFormData({ ...formData, baptismDate: e.target.value })}
                    className="w-full pl-10 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-4 focus:ring-blue-500/10 outline-none"
                  />
                </InputField>

                <InputField label="Departamento / Ministério" icon={Home}>
                  <select
                    value={formData.department}
                    onChange={e => setFormData({ ...formData, department: e.target.value })}
                    className="w-full pl-10 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-4 focus:ring-blue-500/10 outline-none appearance-none"
                  >
                    <option value="">Nenhum / Membro Geral</option>
                    {DEPARTMENTS.map(dept => <option key={dept} value={dept}>{dept}</option>)}
                  </select>
                </InputField>
              </div>
            </section>
          </div>
        </div>

        <div className="flex justify-end space-x-4 pt-10 border-t border-gray-100">
          <button
            type="button" onClick={onCancel}
            className="px-8 py-4 bg-gray-100 text-gray-700 rounded-2xl font-bold hover:bg-gray-200 transition-all"
          >
            Cancelar
          </button>
          <button
            type="submit"
            className="px-10 py-4 bg-blue-800 text-white rounded-2xl font-black hover:bg-blue-900 transition-all shadow-xl shadow-blue-500/20 flex items-center space-x-2 active:scale-95"
          >
            <Save size={20} />
            <span>{initialData ? 'Atualizar Prontuário' : 'Finalizar Cadastro'}</span>
          </button>
        </div>
      </form>
    </div>
  );
};

