      birthDate: formData.birthDate || '',
      category: formData.category || MemberCategory.ADULT,
      gender: formData.gender || Gender.MALE,
      civilStatus: formData.civilStatus || CivilStatus.SINGLE,
      profession: formData.profession,
      nationality: formData.nationality,
      naturalness: formData.naturalness,
      fatherName: formData.fatherName,
      motherName: formData.motherName,
      phone: formData.phone || '',
      address: formData.address || '',
      baptismDate: formData.baptismDate,
      department: formData.department,
      memberSince: formData.memberSince || 'Tempos',
      observations: formData.observations,
      photoUrl: formData.photoUrl,
      createdAt: initialData?.createdAt || new Date().toISOString(),
    };
    onSave(member);
  };

  const calculateCategory = (birthDate: string) => {
    if (!birthDate) return MemberCategory.ADULT;
    const age = Math.floor((new Date().getTime() - new Date(birthDate).getTime()) / 31557600000);
    if (age < 12) return MemberCategory.CHILD;
    if (age < 18) return MemberCategory.YOUTH;
    if (age > 60) return MemberCategory.ELDER;
    return MemberCategory.ADULT;
  };

  const InputField = ({ label, icon: Icon, children, className = "" }: any) => (
    <div className={`space-y-1.5 ${className}`}>
      <label className="text-[10px] font-black text-gray-400 uppercase tracking-[0.15em] block ml-1">{label}</label>
      <div className="relative group">
        {Icon && (
          <div className="absolute inset-y-0 left-0 pl-3.5 flex items-center pointer-events-none text-gray-300 group-focus-within:text-blue-500 transition-colors">
            <Icon size={18} />
          </div>
        )}
        {children}
      </div>
    </div>
  );

  const SectionTitle = ({ icon: Icon, title }: any) => (
    <div className="flex items-center space-x-3 border-b border-gray-100 pb-3 mb-8">
      <div className="p-2.5 bg-blue-50 text-blue-600 rounded-xl shadow-sm">
        <Icon size={20} />
      </div>
      <h3 className="text-xl font-black text-gray-800 tracking-tight">{title}</h3>
    </div>
  );

  return (
    <div className="bg-white rounded-[2.5rem] shadow-2xl overflow-hidden max-w-5xl mx-auto border border-gray-100 mb-20 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="bg-blue-900 p-10 text-white flex flex-col md:flex-row justify-between items-center gap-6">
        <div className="text-center md:text-left">
          <h2 className="text-4xl font-black tracking-tight">{initialData ? 'Editar Prontuário' : 'Novo Cadastro de Membro'}</h2>
          <p className="text-blue-200 mt-2 font-medium">Preencha as informações do irmão(a) para o rol de membros.</p>
        </div>
        <button onClick={onCancel} className="bg-white/10 hover:bg-white/20 p-4 rounded-2xl transition-all active:scale-95 no-print" type="button">
          <ArrowLeft size={24} />
        </button>
      </div>

      <form onSubmit={handleSubmit} className="p-10 lg:p-14 space-y-16">
        <div className="flex flex-col lg:flex-row gap-16">
          {/* Lado Esquerdo: Foto e Status */}
          <div className="flex flex-col items-center space-y-8 lg:w-1/3">
            <div className="w-56 h-64 rounded-[3rem] bg-gray-50 border-8 border-white shadow-2xl overflow-hidden relative group cursor-pointer">
              {photoPreview ? (
                <img src={photoPreview} alt="Preview" className="w-full h-full object-cover" />
              ) : (
                <div className="w-full h-full flex flex-col items-center justify-center text-gray-200">
                  <User size={100} strokeWidth={1} />
                  <span className="text-[10px] font-black uppercase mt-4 tracking-widest text-gray-400">Inserir Foto</span>
                </div>
              )}
              <label className="absolute inset-0 bg-blue-900/80 flex flex-col items-center justify-center opacity-0 group-hover:opacity-100 transition-all duration-300">
                <Camera size={40} className="text-white mb-2" />
                <span className="text-white text-xs font-black uppercase tracking-widest">Alterar</span>
                <input type="file" className="hidden" accept="image/*" onChange={handlePhotoChange} />
              </label>
            </div>

            <div className="w-full space-y-6">
              <InputField label="Classificação Etária" icon={TrendingUp}>
                <select
                  value={formData.category}
                  onChange={e => setFormData({ ...formData, category: e.target.value as MemberCategory })}
                  className="w-full pl-11 pr-4 py-4 bg-gray-50 border border-transparent rounded-2xl focus:bg-white focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 outline-none appearance-none font-black text-blue-900 transition-all cursor-pointer"
                >
                  {Object.values(MemberCategory).map(cat => <option key={cat} value={cat}>{cat}</option>)}
                </select>
              </InputField>

              <InputField label="Membro desde (Escreva normalmente)" icon={Edit3}>
                <input
                  type="text"
                  value={formData.memberSince}
                  onChange={e => setFormData({ ...formData, memberSince: e.target.value })}
                  placeholder="Ex: Tempos, 2010, Infância..."
                  className="w-full pl-11 pr-4 py-4 bg-gray-50 border border-transparent rounded-2xl focus:bg-white focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 outline-none font-bold text-gray-700 transition-all"
                />
              </InputField>
            </div>
          </div>

          {/* Lado Direito: Seções do Formulário */}
          <div className="flex-1 space-y-12">
            <section>
              <SectionTitle icon={User} title="Identificação" />
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <InputField label="Nome Completo do Membro" icon={User} className="md:col-span-2">
                  <input
                    type="text" required value={formData.name}
                    onChange={e => setFormData({ ...formData, name: e.target.value })}
                    className="w-full pl-11 pr-4 py-4 bg-gray-50 border border-transparent rounded-2xl focus:bg-white focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 outline-none font-bold text-gray-800 transition-all"
                    placeholder="Digite o nome completo sem abreviações"
                  />
                </InputField>

                <InputField label="Data de Nascimento" icon={Calendar}>
                  <input
                    type="date" required value={formData.birthDate}
                    onChange={e => {
                      const val = e.target.value;
                      setFormData({ ...formData, birthDate: val, category: calculateCategory(val) });
                    }}
                    className="w-full pl-11 pr-4 py-4 bg-gray-50 border border-transparent rounded-2xl focus:bg-white focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 outline-none font-bold transition-all"
                  />
                </InputField>

                <InputField label="Sexo" icon={User}>
                  <select
                    value={formData.gender}
                    onChange={e => setFormData({ ...formData, gender: e.target.value as Gender })}
                    className="w-full pl-11 pr-4 py-4 bg-gray-50 border border-transparent rounded-2xl focus:bg-white focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 outline-none font-bold transition-all appearance-none cursor-pointer"
                  >
                    <option value={Gender.MALE}>Masculino</option>
                    <option value={Gender.FEMALE}>Feminino</option>
                  </select>
                </InputField>

                <InputField label="Estado Civil" icon={Heart}>
                  <select
                    value={formData.civilStatus}
                    onChange={e => setFormData({ ...formData, civilStatus: e.target.value as CivilStatus })}
                    className="w-full pl-11 pr-4 py-4 bg-gray-50 border border-transparent rounded-2xl focus:bg-white focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 outline-none font-bold transition-all appearance-none cursor-pointer"
                  >
                    {Object.values(CivilStatus).map(status => <option key={status} value={status}>{status}</option>)}
                  </select>
                </InputField>

                <InputField label="WhatsApp / Celular" icon={Phone}>
                  <input
                    type="tel" value={formData.phone}
                    onChange={e => setFormData({ ...formData, phone: e.target.value })}
                    className="w-full pl-11 pr-4 py-4 bg-gray-50 border border-transparent rounded-2xl focus:bg-white focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 outline-none font-bold transition-all"
                    placeholder="(63) 90000-0000"
                  />
                </InputField>

                <InputField label="Endereço (Digitar normalmente)" icon={Home} className="md:col-span-2">
                  <input
                    type="text" value={formData.address}
                    onChange={e => setFormData({ ...formData, address: e.target.value })}
                    className="w-full pl-11 pr-4 py-4 bg-gray-50 border border-transparent rounded-2xl focus:bg-white focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 outline-none font-bold transition-all"
                    placeholder="Ex: Rua Getúlio Vargas, 123, Aguiarnópolis-TO"
                  />
                </InputField>
              </div>
            </section>

            <section>
              <SectionTitle icon={Clipboard} title="Observações e Histórico" />
              <div className="space-y-6">
                <InputField label="Informações Adicionais (Escreva o que desejar)" icon={Edit3}>
                  <textarea
                    rows={4}
                    value={formData.observations || ''}
                    onChange={e => setFormData({ ...formData, observations: e.target.value })}
                    className="w-full pl-11 pr-4 py-4 bg-gray-50 border border-transparent rounded-2xl focus:bg-white focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 outline-none font-medium text-gray-700 transition-all resize-none"
                    placeholder="Digite livremente sobre o membro (ex: talentos, problemas de saúde, cargos anteriores...)"
                  />
                </InputField>
              </div>
            </section>
          </div>
        </div>

        <div className="flex flex-col sm:flex-row justify-end gap-4 pt-10 border-t border-gray-100 no-print">
          <button
            type="button" onClick={onCancel}
            className="px-10 py-5 bg-gray-100 text-gray-500 rounded-2xl font-black hover:bg-gray-200 transition-all active:scale-95"
          >
            Sair sem Salvar
          </button>
          <button
            type="submit"
            className="px-12 py-5 bg-blue-900 text-white rounded-2xl font-black hover:bg-blue-950 transition-all shadow-2xl shadow-blue-900/30 flex items-center justify-center space-x-3 active:scale-95"
          >
            <Save size={24} />
            <span>{initialData ? 'Atualizar Prontuário' : 'Salvar Cadastro'}</span>
          </button>
        </div>
      </form>
    </div>
  );
};

export default MemberForm;

