import React, { useState } from 'react';
import { Member, MemberCategory, Gender, CivilStatus } from '../types';
import { 
  Camera, Save, ArrowLeft, Calendar, User, Phone, Home, 
  MapPin, TrendingUp, Briefcase, Globe, Heart, Users, Edit3, Clipboard
} from 'lucide-react';
import { DEPARTMENTS } from '../constants';

// Componentes auxiliares movidos para fora para evitar perda de foco (re-renders)
const InputField = ({ label, icon: Icon, children, className = "" }: any) => (
  <div className={`space-y-1.5 ${className}`}>
    <label className="text-[10px] font-black text-gray-400 uppercase tracking-[0.15em] block ml-1">{label}</label>
    <div className="relative group">
      {Icon && (
        <div className="absolute inset-y-0 left-0 pl-3.5 flex items-center pointer-events-none text-gray-300 group-focus-within:text-blue-500 transition-colors">
