export enum MemberCategory {
  CHILD = 'Criança',
  YOUTH = 'Jovem',
  ADULT = 'Adulto',
  ELDER = 'Idoso'
}

export enum Gender {
  MALE = 'Masculino',
  FEMALE = 'Feminino'
}

export enum CivilStatus {
  SINGLE = 'Solteiro(a)',
  MARRIED = 'Casado(a)',
  DIVORCED = 'Divorciado(a)',
  WIDOWED = 'Viúvo(a)'
}

export interface Member {
  id: string;
  name: string;
  birthDate: string;
  category: MemberCategory;
  gender: Gender;
  civilStatus: CivilStatus;
  profession?: string;
  nationality?: string;
  naturalness?: string;
  fatherName?: string;
  motherName?: string;
  phone: string;
  address: string;
  baptismDate?: string;
  department?: string;
  photoUrl?: string;
  memberSince?: string;
  observations?: string;
  createdAt: string;
}

export interface Tithe {
  id: string;
  memberId: string;
  memberName: string;
  value: number;
  date: string;
  type: 'Dízimo' | 'Oferta' | 'Missões';
  observations?: string;
}

export type ViewType = 'dashboard' | 'members' | 'register' | 'birthdays' | 'ai-assistant' | 'id-card' | 'documents' | 'tithes';

import React, { useState, useEffect } from 'react';
import { 
  Users, 
  UserPlus, 
  LayoutDashboard, 
  Gift, 
  Menu, 
  X, 
  Building2,
  Sparkles,
  Contact,
  FileText,
  Coins
} from 'lucide-react';
import { Member, Tithe, ViewType } from './types';
import Dashboard from './components/Dashboard';
import MemberList from './components/MemberList';
import MemberForm from './components/MemberForm';
import BirthdayList from './components/BirthdayList';
import AIAssistant from './components/AIAssistant';
import IDCardGenerator from './components/IDCardGenerator';
import DocumentGenerator from './components/DocumentGenerator';
import TitheControl from './components/TitheControl';

const App: React.FC = () => {
  const [members, setMembers] = useState<Member[]>([]);
  const [tithes, setTithes] = useState<Tithe[]>([]);
  const [currentView, setCurrentView] = useState<ViewType>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [editingMember, setEditingMember] = useState<Member | null>(null);

  useEffect(() => {
    const savedMembers = localStorage.getItem('ad_aguiarnopolis_members');
    const savedTithes = localStorage.getItem('ad_aguiarnopolis_tithes');
    if (savedMembers) setMembers(JSON.parse(savedMembers));
    if (savedTithes) setTithes(JSON.parse(savedTithes));
  }, []);

  useEffect(() => {
    localStorage.setItem('ad_aguiarnopolis_members', JSON.stringify(members));
  }, [members]);

  useEffect(() => {
    localStorage.setItem('ad_aguiarnopolis_tithes', JSON.stringify(tithes));
  }, [tithes]);

  const addMember = (newMember: Member) => {
    setMembers(prev => [...prev, newMember]);
    setCurrentView('members');
  };

  const updateMember = (updated: Member) => {
    setMembers(prev => prev.map(m => m.id === updated.id ? updated : m));
    setEditingMember(null);
    setCurrentView('members');
  };

  const deleteMember = (id: string) => {
    if (confirm('Tem certeza que deseja excluir este membro?')) {
      setMembers(prev => prev.filter(m => m.id !== id));
      setTithes(prev => prev.filter(t => t.memberId !== id));
    }
  };

  const addTithe = (tithe: Tithe) => {
    setTithes(prev => [tithe, ...prev]);
  };

  const deleteTithe = (id: string) => {
    if (confirm('Excluir este lançamento financeiro?')) {
      setTithes(prev => prev.filter(t => t.id !== id));
    }
  };

  const handleEdit = (member: Member) => {
    setEditingMember(member);
    setCurrentView('register');
  };

  const NavItem = ({ view, icon: Icon, label }: { view: ViewType, icon: React.ElementType, label: string }) => (
    <button
      onClick={() => {
        setCurrentView(view);
        setEditingMember(null);
        setIsSidebarOpen(false);
      }}
      className={`flex items-center space-x-3 w-full px-4 py-3 rounded-lg transition-all duration-200 ${
        currentView === view 
          ? 'bg-blue-600 text-white shadow-lg scale-105' 
          : 'text-gray-600 hover:bg-blue-50 hover:text-blue-600'
      }`}
      aria-label={label}
    >
      <Icon size={20} />
      <span className="font-medium">{label}</span>
    </button>
  );

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-gray-50">
      <header className="md:hidden bg-blue-900 text-white p-4 flex justify-between items-center sticky top-0 z-50 shadow-md no-print">
        <div className="flex items-center space-x-2">
          <Building2 size={24} className="text-amber-400" />
          <h1 className="text-lg font-bold truncate">AD Aguiarnópolis</h1>
        </div>
        <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-1">
          {isSidebarOpen ? <X size={28} /> : <Menu size={28} />}
        </button>
      </header>

      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/50 z-40 md:hidden backdrop-blur-sm"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      <aside className={`
        fixed inset-y-0 left-0 transform ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
        md:relative md:translate-x-0 transition-transform duration-300 ease-in-out
        z-50 w-64 bg-white border-r border-gray-200 flex flex-col h-screen no-print
      `}>
        <div className="p-6 border-b border-gray-100 hidden md:block">
          <div className="flex items-center space-x-2 mb-2">
            <Building2 size={32} className="text-blue-700" />
            <span className="text-blue-900 font-extrabold text-xl leading-tight">AD Aguiarnópolis</span>
          </div>
          <p className="text-[10px] text-gray-400 uppercase tracking-[0.2em] font-bold">Gestão Institucional</p>
        </div>

        <nav className="flex-1 px-4 py-6 space-y-2 overflow-y-auto">
          <NavItem view="dashboard" icon={LayoutDashboard} label="Dashboard" />
          <NavItem view="members" icon={Users} label="Membros" />
          <NavItem view="register" icon={UserPlus} label={editingMember ? "Editar Membro" : "Novo Membro"} />
          <NavItem view="tithes" icon={Coins} label="Dízimos e Ofertas" />
          <NavItem view="birthdays" icon={Gift} label="Aniversariantes" />
          <NavItem view="id-card" icon={Contact} label="Cartão de Membro" />
          <NavItem view="documents" icon={FileText} label="Cartas e Documentos" />
          <NavItem view="ai-assistant" icon={Sparkles} label="Assistente IA" />
        </nav>

        <div className="p-4 border-t border-gray-100">
          <div className="bg-blue-50 p-4 rounded-2xl">
            <p className="text-xs text-blue-800 font-semibold mb-1">Membros Ativos</p>
            <p className="text-2xl font-black text-blue-900">{members.length}</p>
          </div>
        </div>
      </aside>

      <main className="flex-1 overflow-y-auto p-4 md:p-8">
        <div className="max-w-6xl mx-auto">
          {currentView === 'dashboard' && <Dashboard members={members} tithes={tithes} onNavigate={setCurrentView} />}
          {currentView === 'members' && (
            <MemberList 
              members={members} 
              onDelete={deleteMember} 
              onEdit={handleEdit} 
            />
          )}
          {currentView === 'register' && (
            <MemberForm 
              key={editingMember?.id || 'new'}
              onSave={editingMember ? updateMember : addMember} 
              initialData={editingMember} 
              onCancel={() => {
                setEditingMember(null);
                setCurrentView('members');
              }}
            />
          )}
          {currentView === 'tithes' && (
            <TitheControl 
              members={members} 
              tithes={tithes} 
              onAddTithe={addTithe} 
              onDeleteTithe={deleteTithe} 
            />
          )}
          {currentView === 'birthdays' && <BirthdayList members={members} />}
          {currentView === 'id-card' && <IDCardGenerator members={members} />}
          {currentView === 'documents' && <DocumentGenerator members={members} />}
          {currentView === 'ai-assistant' && <AIAssistant members={members} />}
        </div>
      </main>
    </div>
  );
};

export default App;

import React from 'react';
import { 
  Users, 
  Baby, 
  Cake, 
  Award,
  Building2,
  TrendingUp,
  Coins
} from 'lucide-react';
import { Member, MemberCategory, ViewType, Tithe } from '../types';
import { PieChart, Pie, Cell, ResponsiveContainer, BarChart, Bar, XAxis, YAxis, Tooltip, Legend } from 'recharts';

interface DashboardProps {
  members: Member[];
  tithes?: Tithe[];
  onNavigate: (view: ViewType) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ members, tithes = [], onNavigate }) => {
  const currentMonth = new Date().getMonth();
  const currentYear = new Date().getFullYear();

  const stats = {
    total: members.length,
    children: members.filter(m => m.category === MemberCategory.CHILD).length,
    youth: members.filter(m => m.category === MemberCategory.YOUTH).length,
    adults: members.filter(m => m.category === MemberCategory.ADULT || m.category === MemberCategory.ELDER).length,
    birthdaysThisMonth: members.filter(m => {
      const bDate = new Date(m.birthDate);
      return bDate.getMonth() === currentMonth;
    }).length,
    monthlyTitheTotal: tithes
      .filter(t => {
        const tDate = new Date(t.date);
        return tDate.getMonth() === currentMonth && tDate.getFullYear() === currentYear;
      })
      .reduce((acc, curr) => acc + curr.value, 0)
  };

  const categoryData = [
    { name: 'Crianças', value: stats.children, color: '#3b82f6' },
    { name: 'Jovens', value: stats.youth, color: '#10b981' },
    { name: 'Adultos/Idosos', value: stats.adults, color: '#f59e0b' },
  ];

  const StatCard = ({ title, value, icon: Icon, colorClass, onClick, prefix = "" }: any) => (
    <div 
      onClick={onClick}
      className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex items-center justify-between cursor-pointer hover:shadow-md transition-shadow"
    >
      <div>
        <p className="text-sm font-medium text-gray-500 mb-1">{title}</p>
        <p className="text-2xl font-bold text-gray-900">{prefix}{typeof value === 'number' ? value.toLocaleString('pt-BR', { minimumFractionDigits: 2 }) : value}</p>
      </div>
      <div className={`p-3 rounded-xl ${colorClass}`}>
        <Icon size={24} />
      </div>
    </div>
  );

  return (
    <div className="space-y-8">
      <header>
        <h2 className="text-3xl font-black text-gray-900 tracking-tight">Painel de Gestão</h2>
        <p className="text-gray-500 font-medium">Resumo administrativo da AD Aguiarnópolis.</p>
      </header>

      {/* Grid Stats */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard 
          title="Total de Membros" 
          value={stats.total} 
          icon={Users} 
          colorClass="bg-blue-100 text-blue-600" 
          onClick={() => onNavigate('members')}
        />
        <StatCard 
          title="Arrecadação Mês" 
          value={stats.monthlyTitheTotal} 
          prefix="R$ "
          icon={Coins} 
          colorClass="bg-green-100 text-green-600" 
          onClick={() => onNavigate('tithes')}
        />
        <StatCard 
          title="Aniversariantes (Mês)" 
          value={stats.birthdaysThisMonth} 
          icon={Cake} 
          colorClass="bg-pink-100 text-pink-600"
          onClick={() => onNavigate('birthdays')}
        />
        <StatCard 
          title="Crianças" 
          value={stats.children} 
          icon={Baby} 
          colorClass="bg-indigo-100 text-indigo-600" 
          onClick={() => onNavigate('members')}
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
          <h3 className="text-lg font-bold text-gray-900 mb-6">Distribuição por Categoria</h3>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={categoryData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {categoryData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color} />
                  ))}
                </Pie>
                <Tooltip />
                <Legend verticalAlign="bottom" height={36}/>
              </PieChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-blue-900 text-white p-8 rounded-[2.5rem] flex flex-col justify-center relative overflow-hidden shadow-2xl">
          <div className="relative z-10">
            <h3 className="text-2xl font-black mb-4">Ação Rápida</h3>
            <p className="text-blue-100 mb-8 font-medium">Lançar um novo dízimo ou oferta recebida agora.</p>
            <button 
              onClick={() => onNavigate('tithes')}
              className="bg-amber-400 text-blue-950 px-8 py-4 rounded-2xl font-black hover:bg-amber-300 transition-all shadow-xl active:scale-95 flex items-center space-x-2"
            >
              <Coins size={20} />
              <span>Lançar Dízimo</span>
            </button>
          </div>
          <div className="absolute top-0 right-0 -mt-10 -mr-10 opacity-10 transform scale-150">
            <Coins size={200} />
          </div>
        </div>
      </div>
    </div>
  );
};

