                  className="w-full px-4 py-3 bg-gray-50 border border-transparent rounded-xl focus:bg-white focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 outline-none font-medium text-sm transition-all resize-none"
                  rows={2} placeholder="Ex: Referente ao mês de..."
                />
              </div>
            </div>

            <button
              type="submit"
              className="w-full py-4 bg-blue-700 text-white rounded-2xl font-black hover:bg-blue-800 transition-all shadow-xl shadow-blue-500/20 flex items-center justify-center space-x-2 active:scale-95"
            >
              <CheckCircle2 size={20} />
              <span>Confirmar Lançamento</span>
            </button>
          </form>
        </div>

        {/* Histórico de Lançamentos */}
        <div className="lg:col-span-2 space-y-6">
          <div className="flex items-center justify-between">
            <h3 className="text-xl font-black text-gray-800">Últimos Lançamentos</h3>
            <div className="relative group">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
              <input
                type="text" placeholder="Filtrar por nome..."
                value={searchTerm} onChange={e => setSearchTerm(e.target.value)}
                className="pl-10 pr-4 py-2 bg-white border border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none w-64 shadow-sm text-sm"
              />
            </div>
          </div>

          <div className="bg-white rounded-[2rem] border border-gray-100 shadow-sm overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-gray-50 border-b border-gray-100">
                  <tr>
                    <th className="px-6 py-4 text-[10px] font-black text-gray-400 uppercase tracking-widest">Membro</th>
                    <th className="px-6 py-4 text-[10px] font-black text-gray-400 uppercase tracking-widest">Data</th>
                    <th className="px-6 py-4 text-[10px] font-black text-gray-400 uppercase tracking-widest">Tipo</th>
                    <th className="px-6 py-4 text-[10px] font-black text-gray-400 uppercase tracking-widest text-right">Valor</th>
                    <th className="px-6 py-4 text-[10px] font-black text-gray-400 uppercase tracking-widest text-center">Ação</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-50">
                  {filteredTithes.length > 0 ? (
                    filteredTithes.map(t => (
                      <tr key={t.id} className="hover:bg-gray-50/50 transition-colors group">
                        <td className="px-6 py-4">
                          <p className="font-bold text-gray-800">{t.memberName}</p>
                          {t.observations && <p className="text-[10px] text-gray-400 truncate max-w-[150px]">{t.observations}</p>}
                        </td>
                        <td className="px-6 py-4 text-sm text-gray-500">
                          {new Date(t.date).toLocaleDateString('pt-BR')}
                        </td>
                        <td className="px-6 py-4">
                          <span className={`text-[10px] font-black px-2 py-1 rounded-md uppercase tracking-wider ${
                            t.type === 'Dízimo' ? 'bg-blue-100 text-blue-700' : 
                            t.type === 'Missões' ? 'bg-indigo-100 text-indigo-700' : 'bg-green-100 text-green-700'
                          }`}>
                            {t.type}
                          </span>
                        </td>
                        <td className="px-6 py-4 text-right">
                          <p className="font-black text-gray-900">R$ {t.value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
                        </td>
                        <td className="px-6 py-4 text-center">
                          <button 
                            onClick={() => onDeleteTithe(t.id)}
                            className="p-2 text-gray-300 hover:text-red-500 transition-colors"
                          >
                            <Trash2 size={18} />
                          </button>
                        </td>
                      </tr>
                    ))
                  ) : (
                    <tr>
                      <td colSpan={5} className="px-6 py-20 text-center text-gray-400">
                        <Coins size={48} className="mx-auto mb-4 opacity-10" />
                        <p className="font-bold">Nenhum lançamento encontrado.</p>
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

